import { useEffect, useState } from "react";
import API from "../api";

const MyBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const res = await API.get("/bookings/my");
        setBookings(res.data.bookings);
      } catch (err) {
        console.log(err);
      } finally {
        setLoading(false);
      }
    };
    fetchBookings();
  }, []);

  const handleCancel = async (id) => {
    try {
      await API.put(`/bookings/${id}/cancel`);
      setBookings(bookings.map(b => b._id === id ? { ...b, status: "cancelled", paymentStatus: "unpaid" } : b));
    } catch (err) {
      console.log(err);
    }
  };

  if (loading) return <p className="text-center mt-10">Loading...</p>;

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6">My Bookings</h1>
      {bookings.length === 0 ? <p>No bookings yet.</p> : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {bookings.map(b => (
            <div key={b._id} className="bg-white shadow p-4 rounded-lg">
              <h2 className="font-bold text-xl">{b.event.name}</h2>
              <p>{new Date(b.event.date).toLocaleDateString()} - {b.event.venue}</p>
              <p>Tickets: {b.numberOfTickets}</p>
              <p>Status: <span className={`font-semibold ${b.status === "confirmed" ? "text-green-600" : b.status === "cancelled" ? "text-red-600" : "text-yellow-600"}`}>{b.status}</span></p>
              <p>Payment: <span className={`font-semibold ${b.paymentStatus === "paid" ? "text-green-600" : b.paymentStatus === "refunded" ? "text-blue-600" : "text-red-600"}`}>{b.paymentStatus}</span></p>
              {b.status !== "cancelled" && (
                <button onClick={() => handleCancel(b._id)} className="mt-2 bg-red-600 text-white px-4 py-1 rounded">Cancel Booking</button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MyBookings;
